const express = require("express");
const pptxgen = require("pptxgenjs");
const React = require("react");
const ReactDOMServer = require("react-dom/server");
const sharp = require("sharp");

const app = express();
app.use(express.json());

// ─── LOGO (two variants — backgrounds are baked into each file, not
// transparent, so each is only ever used on its matching slide color) ──
const LOGO_DARK_B64 = "image/png;base64,";
const LOGO_LIGHT_B64 = "image/png;base64,";

// ─── HERO ART: Burj Khalifa silhouette (white on transparent) ─────
// Generated illustration, not a photograph — no copyright/licensing risk.
const BURJ_B64 = "image/png;base64,";

// ─── BRAND PALETTE ────────────────────────────────────────────────
// Black dominates (cover + close). White content slides. Red is a precision
// accent only — used on numerals, single words, and key stats. Never as a
// background fill, border, or decorative stripe.
const C = {
  black:     "0A0A0A",
  white:     "FFFFFF",
  red:       "CC0000",
  ink:       "1A1A1A",   // body text on white slides
  muted:     "6B6B6B",   // captions on white slides
  mutedDark: "9A9A9A",   // captions on black slides
  hairline:  "E4E4E4",   // subtle dividers on white slides (not under titles)
};

const FONT_HEAD = "Arial";   // safe-list, true-to-width in QA
const FONT_BODY = "Calibri"; // safe-list

// ─── ICON HELPER ─────────────────────────────────────────────────
async function iconBase64(iconPath, color, size = 256) {
  try {
    const [lib, name] = iconPath.split("/");
    const icons = require(`react-icons/${lib}`);
    const Icon = icons[name];
    if (!Icon) throw new Error(`Icon not found: ${iconPath}`);
    const svg = ReactDOMServer.renderToStaticMarkup(
      React.createElement(Icon, { color, size: String(size) })
    );
    const buf = await sharp(Buffer.from(svg)).png().toBuffer();
    return "image/png;base64," + buf.toString("base64");
  } catch (err) {
    const fallback = `<svg xmlns="http://www.w3.org/2000/svg" width="${size}" height="${size}" viewBox="0 0 ${size} ${size}"><circle cx="${size/2}" cy="${size/2}" r="${size/3}" fill="${color}"/></svg>`;
    const buf = await sharp(Buffer.from(fallback)).png().toBuffer();
    return "image/png;base64," + buf.toString("base64");
  }
}

const ICON_ALIASES = {
  FaGoogle: "FaSearch", FaInstagram: "FaCamera", FaFacebook: "FaThumbsUp",
  FaTwitter: "FaComment", FaLinkedin: "FaBriefcase", FaYoutube: "FaPlay",
  FaTiktok: "FaVideo", FaWhatsapp: "FaPhone", FaSeo: "FaSearch",
  FaAnalytics: "FaChartBar", FaMarketing: "FaBullhorn", FaAds: "FaBullseye",
  FaConversion: "FaChartLine", FaReviews: "FaStar", FaLocal: "FaMapMarkerAlt",
  FaGrowth: "FaChartLine", FaReputation: "FaShieldAlt", FaVisibility: "FaEye",
  FaRanking: "FaTrophy", FaLeads: "FaUsers", FaRevenue: "FaDollarSign",
  FaSpeed: "FaRocket", FaWebsite: "FaGlobe", FaBrand: "FaPaintBrush",
  FaContent: "FaPen", FaEmail: "FaEnvelope",
};

function safeFaIcon(name) {
  if (!name) return "FaArrowUp";
  const cleaned = name.trim();
  let resolved;
  if (/^Fa[A-Z]/.test(cleaned)) resolved = cleaned;
  else if (/^[A-Z]/.test(cleaned)) resolved = "Fa" + cleaned;
  else resolved = "Fa" + cleaned.charAt(0).toUpperCase() + cleaned.slice(1);
  return ICON_ALIASES[resolved] || resolved;
}

// ─── TEXT FIT HELPER ──────────────────────────────────────────────
// Conservative size steps so long Claude output never overflows its box.
function fitSize(text, { max, min, hardLen, softLen }) {
  const len = String(text || "").length;
  if (len <= softLen) return max;
  if (len >= hardLen) return min;
  const ratio = (len - softLen) / (hardLen - softLen);
  return Math.round(max - ratio * (max - min));
}

// ─── LOGO PLACEMENT ────────────────────────────────────────────────
// Small, top-left, identical position on every slide. variant picks the
// correctly-colored file for the slide's background — "light" (white+red
// text) for black slides, "dark" (black+red text) for white slides.
function placeLogo(slide, variant = "dark") {
  const data = variant === "light" ? LOGO_LIGHT_B64 : LOGO_DARK_B64;
  // Source is 750x200 (3.75:1) — keep that ratio so it never stretches
  slide.addImage({ data, x: 0.45, y: 0.32, w: 1.35, h: 0.36 });
}

async function generateDeck(data) {
  const {
    company_name = "Client",
    website = "",
    audit_score = "N/A",
    headline = "Here is exactly what we found on your business.",
    problem_1 = "", problem_2 = "", problem_3 = "",
    solution_1 = "", solution_2 = "", solution_3 = "",
    solution_icon_1, solution_icon_2, solution_icon_3,
    proof_stat_1 = "620+", proof_label_1 = "Direct reservations in 30 days",
    proof_stat_2 = "24K", proof_label_2 = "New subscribers in 60 days",
    proof_stat_3 = "200+", proof_label_3 = "Qualified leads in 60 days",
    offer_line = "Only 3 strategy spots left this month.",
    cta_line = "Book Your Free Strategy Call",
  } = data;

  const icons = [
    "fa/" + safeFaIcon(solution_icon_1 || "FaSearch"),
    "fa/" + safeFaIcon(solution_icon_2 || "FaBullseye"),
    "fa/" + safeFaIcon(solution_icon_3 || "FaChartLine"),
  ];
  // Icons render in black — they sit on white cards, never on red/dark fills.
  const sIcons = await Promise.all(icons.map(i => iconBase64(i, "#0A0A0A", 160)));

  const pres = new pptxgen();
  pres.layout = "LAYOUT_16x9"; // 10in x 5.63in

  const safeName = String(company_name).replace(/[^a-z0-9]/gi, "_").toUpperCase();

  // ============================================================
  // SLIDE 1 — COVER. Black. Text claims the left half, the Burj
  // Khalifa skyline owns the right half — Dubai's skyline doing
  // the visual work instead of empty black space.
  // ============================================================
  {
    const s = pres.addSlide();
    s.background = { color: C.black };
    placeLogo(s, "light");

    // Burj Khalifa illustration — right half, full height, anchored
    // to the bottom so the tower appears to rise from the slide edge.
    s.addImage({ data: BURJ_B64, x: 5.35, y: 0.0, w: 4.65, h: 5.63 });

    // The diagnostic line — left column, the whole point of the cover
    const hlSize = fitSize(headline, { max: 32, min: 22, softLen: 35, hardLen: 80 });
    s.addText(headline, {
      x: 0.55, y: 1.85, w: 4.55, h: 2.1,
      fontSize: hlSize, fontFace: FONT_HEAD, color: C.white, bold: true,
      margin: 0, lineSpacingMultiple: 1.08, valign: "top",
    });

    // Company name — small, confident, sits below the line it earned
    s.addText(company_name, {
      x: 0.55, y: 4.0, w: 4.5, h: 0.4,
      fontSize: 13, fontFace: FONT_BODY, color: C.mutedDark, margin: 0,
    });

    // Score sits bottom-left under the company name, quiet
    s.addText([
      { text: String(audit_score), options: { fontSize: 26, color: C.red, bold: true, fontFace: FONT_HEAD } },
      { text: " / 100", options: { fontSize: 12, color: C.mutedDark, fontFace: FONT_BODY } },
    ], { x: 0.55, y: 4.85, w: 3, h: 0.5, align: "left", margin: 0 });
    s.addText("CURRENT DIGITAL SCORE", {
      x: 0.55, y: 5.32, w: 3, h: 0.22,
      fontSize: 7.5, fontFace: FONT_BODY, color: C.mutedDark,
      charSpacing: 2, align: "left", margin: 0,
    });
  }

  // ============================================================
  // SLIDE 2 — THE DIAGNOSIS. White. Three problems as a vertical
  // list with large ghosted numerals as the visual motif. More
  // generous vertical rhythm and bigger numerals than a typical
  // template would risk — this is the slide that earns trust.
  // ============================================================
  {
    const s = pres.addSlide();
    s.background = { color: C.white };
    placeLogo(s, "dark");

    s.addText("What's actually happening", {
      x: 0.6, y: 0.95, w: 8.8, h: 0.6,
      fontSize: 32, fontFace: FONT_HEAD, color: C.black, bold: true, margin: 0,
    });
    s.addText(company_name.toUpperCase(), {
      x: 0.6, y: 1.55, w: 8, h: 0.3,
      fontSize: 10, fontFace: FONT_BODY, color: C.muted,
      charSpacing: 2, bold: true, margin: 0,
    });

    const problems = [problem_1, problem_2, problem_3];
    const rowTop = 2.05, rowH = 1.12, gap = 0.10;

    problems.forEach((prob, i) => {
      const y = rowTop + i * (rowH + gap);
      const pSize = fitSize(prob, { max: 13.5, min: 9.5, softLen: 140, hardLen: 320 });

      // Numeral as motif — large, bold red, the dominant visual element
      s.addText(`0${i + 1}`, {
        x: 0.5, y: y - 0.10, w: 1.1, h: 1.05,
        fontSize: 50, fontFace: FONT_HEAD, color: C.red, bold: true,
        margin: 0, valign: "top",
      });

      s.addText(prob, {
        x: 1.65, y: y + 0.02, w: 7.75, h: rowH - 0.04,
        fontSize: pSize, fontFace: FONT_BODY, color: C.ink,
        margin: 0, valign: "top", lineSpacingMultiple: 1.2,
      });

      // Hairline divider between rows only (not under the title)
      if (i < problems.length - 1) {
        s.addShape("line", {
          x: 1.65, y: y + rowH + gap / 2, w: 7.75, h: 0,
          line: { color: C.hairline, width: 0.75 },
        });
      }
    });
  }

  // ============================================================
  // SLIDE 3 — THE FIX. White. Three columns, icon-in-circle motif,
  // sized and spaced to fill the full slide height — no dead space
  // at the bottom. A footer rule anchors the bottom edge.
  // ============================================================
  {
    const s = pres.addSlide();
    s.background = { color: C.white };
    placeLogo(s, "dark");

    s.addText("How we fix it", {
      x: 0.6, y: 0.95, w: 8.8, h: 0.6,
      fontSize: 32, fontFace: FONT_HEAD, color: C.black, bold: true, margin: 0,
    });
    s.addText("Three moves. In order. Starting immediately.", {
      x: 0.6, y: 1.55, w: 8, h: 0.3,
      fontSize: 12.5, fontFace: FONT_BODY, color: C.muted, margin: 0,
    });

    const sols = [solution_1, solution_2, solution_3];
    const colW = 2.83, colGap = 0.25, startX = 0.6, top = 2.15;
    const circleD = 0.85;

    sols.forEach((sol, i) => {
      const x = startX + i * (colW + colGap);
      const solSize = fitSize(sol, { max: 14, min: 10.5, softLen: 90, hardLen: 160 });

      // Larger icon circle, the visual anchor of each column
      s.addShape("ellipse", {
        x: x, y: top, w: circleD, h: circleD,
        fill: { color: C.white },
        line: { color: C.black, width: 1.5 },
      });
      s.addImage({ data: sIcons[i], x: x + circleD / 2 - 0.22, y: top + circleD / 2 - 0.22, w: 0.44, h: 0.44 });

      s.addText(`STEP 0${i + 1}`, {
        x: x, y: top + circleD + 0.18, w: colW, h: 0.26,
        fontSize: 10, fontFace: FONT_BODY, color: C.red,
        bold: true, charSpacing: 2, margin: 0,
      });

      s.addText(sol, {
        x: x, y: top + circleD + 0.52, w: colW, h: 1.7,
        fontSize: solSize, fontFace: FONT_BODY, color: C.ink,
        margin: 0, lineSpacingMultiple: 1.28, valign: "top",
      });

      // Bottom-anchored hairline under each column, fills the lower
      // third of the slide so nothing reads as empty/unfinished
      s.addShape("line", {
        x: x, y: 4.95, w: colW, h: 0,
        line: { color: C.hairline, width: 0.75 },
      });
    });

    // Bottom strip — confident closing line, anchors the full width
    s.addText("Every move is sequenced. Nothing launches out of order.", {
      x: 0.6, y: 5.12, w: 8.8, h: 0.35,
      fontSize: 11, fontFace: FONT_BODY, italic: true, color: C.muted, margin: 0,
    });
  }

  // ============================================================
  // SLIDE 4 — EVIDENCE. White. Stat numbers dominate the slide —
  // bigger than a typical template would risk — with the labels
  // and closing line giving the lower half real weight too.
  // ============================================================
  {
    const s = pres.addSlide();
    s.background = { color: C.white };
    placeLogo(s, "dark");

    s.addText("This isn't theory", {
      x: 0.6, y: 0.95, w: 8.8, h: 0.6,
      fontSize: 32, fontFace: FONT_HEAD, color: C.black, bold: true, margin: 0,
    });
    s.addText("Results from work we've already shipped", {
      x: 0.6, y: 1.55, w: 8, h: 0.3,
      fontSize: 12.5, fontFace: FONT_BODY, color: C.muted, margin: 0,
    });

    const stats = [
      [proof_stat_1, proof_label_1],
      [proof_stat_2, proof_label_2],
      [proof_stat_3, proof_label_3],
    ];
    const colW = 2.83, colGap = 0.25, startX = 0.6, top = 2.05;

    stats.forEach(([stat, label], i) => {
      const x = startX + i * (colW + colGap);
      const statLen = String(stat).length;
      const statSize = statLen > 6 ? 54 : statLen > 4 ? 66 : 76;

      s.addText(stat, {
        x: x, y: top, w: colW, h: 1.55,
        fontSize: statSize, fontFace: FONT_HEAD, color: C.black, bold: true,
        margin: 0, valign: "bottom",
      });

      // Thin rule under the number — the only separator on the slide
      s.addShape("line", {
        x: x, y: top + 1.65, w: colW * 0.55, h: 0,
        line: { color: C.red, width: 2.5 },
      });

      s.addText(label, {
        x: x, y: top + 1.80, w: colW, h: 0.95,
        fontSize: 11.5, fontFace: FONT_BODY, color: C.muted,
        margin: 0, lineSpacingMultiple: 1.2, valign: "top",
      });
    });

    // Full-width hairline anchors the bottom section
    s.addShape("line", {
      x: 0.6, y: 4.95, w: 8.8, h: 0,
      line: { color: C.hairline, width: 0.75 },
    });

    s.addText("Every number above is a documented client outcome, not a projection.", {
      x: 0.6, y: 5.12, w: 8.8, h: 0.35,
      fontSize: 11.5, fontFace: FONT_BODY, italic: true, color: C.muted, margin: 0,
    });
  }

  // ============================================================
  // SLIDE 5 — NEXT STEP. Black. One CTA. The title is now a direct
  // address to the prospect, not a soft transition phrase — this is
  // the line that should feel like a closing argument, not a label.
  // ============================================================
  {
    const s = pres.addSlide();
    s.background = { color: C.black };
    placeLogo(s, "light");

    s.addText("This is the easy part.", {
      x: 0.6, y: 1.4, w: 8.5, h: 1.0,
      fontSize: 38, fontFace: FONT_HEAD, color: C.white, bold: true,
      margin: 0, lineSpacingMultiple: 1.05,
    });
    s.addText("Everything above is already built. We just need your go-ahead.", {
      x: 0.6, y: 2.35, w: 7.8, h: 0.5,
      fontSize: 14, fontFace: FONT_BODY, color: C.mutedDark, margin: 0,
    });

    const offerSize = fitSize(offer_line, { max: 15, min: 11, softLen: 50, hardLen: 100 });
    s.addText(offer_line, {
      x: 0.6, y: 2.95, w: 7.5, h: 0.5,
      fontSize: offerSize, fontFace: FONT_BODY, color: C.red, bold: true, margin: 0,
    });

    // CTA — solid red fill is the one place red is used as a block,
    // because it is the single action on the slide, not decoration.
    s.addShape("rect", {
      x: 0.6, y: 3.55, w: 3.3, h: 0.62,
      fill: { color: C.red }, line: { color: C.red, width: 0 },
    });
    s.addText(cta_line, {
      x: 0.6, y: 3.55, w: 3.3, h: 0.62,
      fontSize: 13, fontFace: FONT_HEAD, color: C.white, bold: true,
      align: "center", valign: "middle", margin: 0, underline: { style: "none" },
      hyperlink: { url: "https://calendly.com/contact-pro-scalemedia/30min", color: C.white },
    });

    // Calendly link — white, matching the black background's natural
    // contrast, homogeneous with the CTA button's white text.
    s.addText("calendly.com/contact-pro-scalemedia/30min", {
      x: 0.6, y: 4.38, w: 5, h: 0.3,
      fontSize: 10, fontFace: FONT_BODY, color: C.white, margin: 0, underline: { style: "none" },
      hyperlink: { url: "https://calendly.com/contact-pro-scalemedia/30min", color: C.white },
    });

    s.addText("contact@pro-scalemedia.com   ·   pro-scalemedia.com   ·   Dubai, UAE", {
      x: 0.6, y: 5.15, w: 8.5, h: 0.3,
      fontSize: 9, fontFace: FONT_BODY, color: C.mutedDark, margin: 0,
    });
  }

  return await pres.write({ outputType: "nodebuffer" });
}

// ─── ROUTES (unchanged) ────────────────────────────────────────────
app.get("/health", (req, res) => res.json({ status: "ok", service: "ProScaleMEDIA PPTX API" }));

app.post("/generate", async (req, res) => {
  try {
    const data = req.body;
    if (!data || !data.company_name) return res.status(400).json({ error: "company_name is required" });
    console.log(`[PPTX] Generating deck for: ${data.company_name}`);
    const buffer = await generateDeck(data);
    const safeName = String(data.company_name).replace(/[^a-z0-9]/gi, "_").toUpperCase();
    const filename = `ProScaleMEDIA_${safeName}.pptx`;
    res.setHeader("Content-Type", "application/vnd.openxmlformats-officedocument.presentationml.presentation");
    res.setHeader("Content-Disposition", `attachment; filename="${filename}"`);
    res.send(buffer);
    console.log(`[PPTX] Sent ${buffer.length} bytes — ${filename}`);
  } catch (err) {
    console.error("[PPTX] Error:", err.message);
    res.status(500).json({ error: err.message, stack: err.stack });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`[PPTX] ProScaleMEDIA API running on port ${PORT}`));
